mapper.select:
/* wms-inbound-b2blabel-receive-sql-oracle.xml - deleteInterfaceB2blabelReceive - b2b 출고 수신 인터페이스 삭제 */
DELETE FROM TWORK_INTF_B2B_OB_LABEL
 WHERE DLV_BOX_NO = #{dlvBoxNo}
   AND DLV_BOX_BCD = #{dlvBoxBcd}
   AND ITM_CD = #{itmCd}

mapper.insert:
/* wms-inbound-b2blabel-receive-sql-oracle.xml - insertInterfaceB2blabelReceive - b2b 출고 수신 인터페이스 등록 */
INSERT INTO TWORK_INTF_B2B_OB_LABEL
(
	  DLV_BOX_NO
	, DLV_BOX_BCD
	, WRK_DATE
	, GI_DATE
	, BATCH_NO
	, SHOP_CD
	, REC_WHS_COD
	, WHS_COD
	, EQMT_TYP_CD
	, GI_ORD_NO
	, ITM_CD
	, LOAD_QTY
	, ITM_PKG_UNIT_CD
	, FLR_TBL_NO
	, LOT_NO
	, DLV_BOX_CTNR_NO
	, DLV_PLT_CTNR_NO
	, LCS_RT_FUL_RT_NO
	, PRCSYN
	, PRCSDATE
	, RCVDATE
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
)
VALUES
(
	  #{dlvBoxNo}
	, #{dlvBoxBcd}
	, #{wrkDate}
	, #{giDate}
	, #{batchNo}
	, #{shopCd}
	, #{recWhsCod}
	, #{whsCod}
	, #{eqmtTypCd}
	, #{giOrdNo}
	, #{itmCd}
	, #{loadQty}
	, #{itmPkgUnitCd}
	, #{flrTblNo}
	, #{lotNo}
	, #{dlvBoxCtnrNo}
	, #{dlvPltCtnrNo}
	, #{lcsRtFulRtNo}
	, 'N'
	, NULL
	, #{sysdate}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)

mapper.select:
/* wms-inbound-b2blabel-receive-sql-oracle.xml - selectB2blabelCount - B2b 출고라벨 조회 */
SELECT COUNT(*)
  FROM TWORK_INFO_B2B_OB_LABEL
 WHERE CTKEY = #{ctkey}
   AND BOXLABELNO = #{boxlabelno}
   AND SHMISTNO = #{extorderkey}
   AND ICKEY = #{ickey}

mapper.delete:
/* wms-inbound-b2blabel-receive-sql-oracle.xml - deleteB2blabel - B2b 출고라벨 조회 */
DELETE FROM TWORK_INFO_B2B_OB_LABEL
 WHERE CTKEY = #{ctkey}
   AND BOXLABELNO = #{boxlabelno}
   AND SHMISTNO = #{extorderkey}
   AND ICKEY = #{ickey}

mapper.select:
/* wms-inbound-b2blabel-receive-sql-oracle.xml - selectIbdtMap - b2b 출고 수신 인터페이스 - 입고 상세 조회 */
SELECT IBHDKEY
	 , IBDTKEY
	 , OWKEY
  FROM TWORK_INFO_IB_DT
 WHERE CTKEY = #{ctkey}
   AND EXTORDERKEY = #{extorderkey}
   AND ICKEY = #{ickey}

mapper.insert:
/* wms-inbound-b2blabel-receive-sql-oracle.xml - insertB2blabel - b2b 출고 라벨 정보 등록 */
INSERT INTO TWORK_INFO_B2B_OB_LABEL
(
	CTKEY
	, OWKEY
	, BOXLABELNO
	, DLVYDAY
	, SHMISTNO
	, REGDATE
	, IBHDKEY
	, IBDTKEY
	, ICKEY
	, QTY
	, UOM
	, EXPDATE
	, AFCHGEXPDATE
	, CNTRLABELNO
	, CNTRLABELDIVCD
	, IBCFSEQNO
	, IBQTY
	, PRCSYN
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
)
VALUES
(
	#{ctkey}
	, #{owkey}
	, #{boxlabelno}
	, #{dlvyday}
	, #{extorderkey}
	, #{sysdate}
	, #{ibhdkey}
	, #{ibdtkey}
	, #{ickey}
	, #{qty}
	, #{uom}
	, #{expdate}
	, NULL
	, #{cntrlabelno}
	, CASE SUBSTR(#{cntrlabelno}, 1, 1) WHEN 'R' THEN '10' WHEN 'P' THEN '20' ELSE '30' END
	, NULL
	, 0
	, 'N'
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)

mapper.update:
UPDATE TWORK_INTF_B2B_OB_LABEL
   SET PRCSYN = 'Y'
	 , PRCSDATE = #{sysdate}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE OBLABELSEQNO = #{oblabelseqno}
